+import type { ChildProcess } from "node:child_process";
+import { writeFileSync } from "node:fs";
+import { describe, expect, it } from "vitest";
+import { runCliModel } from "../src/llm/cli.js";
+import type { ExecFileFn } from "../src/markitdown.js";
+
+describe("runCliModel regressions", () => {
+  it("streams OpenClaw prompts over stdin instead of --message args", async () => {
+    const seenArgs: string[][] = [];
+    const stdinWrites: string[] = [];
+    const execFileImpl: ExecFileFn = ((_cmd, args, _opts, cb) => {
+      seenArgs.push(args);
+      cb?.(
+        null,
+        JSON.stringify({
+          result: {
+            payloads: [{ text: "hello from openclaw" }],
+          },
+        }),
+        "",
+      );
+      return {
+        stdin: {
+          write(value: string) {
+            stdinWrites.push(value);
+          },
+          end() {},
+        },
+      } as unknown as ChildProcess;
+    }) as ExecFileFn;
+
+    const prompt = "Large prompt body that should not become a CLI argument.";
+    const result = await runCliModel({
+      provider: "openclaw",
+      prompt,
+      model: "main",
+      allowTools: false,
+      timeoutMs: 1000,
+      env: {},
+      execFileImpl,
+      config: null,
+    });
+
+    expect(result.text).toBe("hello from openclaw");
+    expect(seenArgs[0]).toContain("-");
+    expect(seenArgs[0]).not.toContain("--message");
+    expect(seenArgs[0]).not.toContain(prompt);
+    expect(stdinWrites.join("")).toBe(prompt);
+  });
+
+  it("codex extracts assistant text from JSONL stdout when last-message is blank", async () => {
+    const result = await runCliModel({
+      provider: "codex",
+      prompt: "hi",
+      model: null,
+      allowTools: false,
+      timeoutMs: 1000,
+      env: {},
+      config: null,
+      execFileImpl: (_cmd, args, _opts, cb) => {
+        const outputIndex = args.indexOf("--output-last-message");
+        const outputPath = outputIndex >= 0 ? args[outputIndex + 1] : null;
+        if (!outputPath) throw new Error("missing output path");
+        writeFileSync(outputPath, "   ", "utf8");
+        cb(
+          null,
+          [
+            '{"type":"thread.started","thread_id":"abc"}',
+            '{"type":"response.output_text.delta","delta":"Hello"}',
+            '{"type":"response.output_text.delta","delta":" world"}',
+          ].join("\n"),
+          "",
+        );
+        return { stdin: { write() {}, end() {} } } as unknown as ChildProcess;
+      },
+    });
+
+    expect(result.text).toBe("Hello world");
+  });
+
+  it("codex does not leak lifecycle JSONL when no assistant text was produced", async () => {
+    await expect(
+      runCliModel({
+        provider: "codex",
+        prompt: "hi",
+        model: null,
+        allowTools: false,
+        timeoutMs: 1000,
+        env: {},
+        config: null,
